+/**
+ * Sanitize an SVG string to remove executable/scriptable content.
+ * Scratch projects can contain user-controlled SVG; this renderer must not allow
+ * script execution via <script>, event handler attributes, or javascript: URLs.
+ * @param {string} svgString - raw SVG text
+ * @returns {string} sanitized SVG text
+ */
+const sanitizeSvgString = function (svgString) {
+    if (!svgString) return svgString;
+
+    // Remove script-capable elements.
+    // <foreignObject> can embed HTML and enable script execution in some contexts.
+    svgString = svgString
+        .replace(/<script[\s\S]*?>[\s\S]*?<\/script\s*>/gi, '')
+        .replace(/<foreignObject[\s\S]*?>[\s\S]*?<\/foreignObject\s*>/gi, '');
+
+    // Remove inline event handlers (e.g. onload=, onclick=) which can execute JS.
+    svgString = svgString.replace(/\son[a-z]+\s*=\s*(".*?"|'.*?'|[^\s>]+)/gi, '');
+
+    const isUnsafeUrl = function (url) {
+        const value = String(url).trim().toLowerCase();
+        if (!value) return false;
+        if (value.indexOf('javascript:') === 0) return true;
+        if (value.indexOf('vbscript:') === 0) return true;
+        // Only allow a small set of safe data: image types; block others (including SVG).
+        if (value.indexOf('data:') === 0 && !/^data:image\/(png|gif|jpe?g|webp|bmp);/i.test(value)) return true;
+        return false;
+    };
+
+    // Remove dangerous URL-based attributes.
+    svgString = svgString.replace(
+        /\s(?:xlink:href|href|src)\s*=\s*("([^"]*)"|'([^']*)'|([^\s>]+))/gi,
+        (match, _all, dQuote, sQuote, bare) => {
+            const val = dQuote || sQuote || bare || '';
+            return isUnsafeUrl(val) ? '' : match;
+        }
+    );
+
+    // Sanitize style attributes that may contain url(javascript:...)
+    svgString = svgString.replace(
+        /\sstyle\s*=\s*("([^"]*)"|'([^']*)')/gi,
+        (match, all, dQuote, sQuote) => {
+            const styleValue = dQuote || sQuote || '';
+            const sanitized = styleValue.replace(/url\(\s*(['"]?)(.*?)\1\s*\)/gi, (m, q, u) => {
